    fn test_u256_to_f64_scaled_overflow() {
        // Test value exceeding precision limit (> 1e13 unscaled)
        // 2e13 * 1e18 = 2e31
        let overflow_value =
            U256::from(20_000_000_000_000u128) * U256::from(1_000_000_000_000_000_000u128);
        let result = u256_to_f64_scaled(overflow_value);
        assert!(result.is_err());
